mapper.select:
SELECT menu_id, menu_name, parent_id, order_num, path, component, `query`, is_frame, is_cache, menu_type, visible, status, perms, icon, create_time FROM sys_menu WHERE deleted = 0
AND menu_name LIKE CONCAT('%', #{menuName}, '%')
AND visible = #{visible}
AND status = #{status}
ORDER BY parent_id, order_num

SELECT menu_id, menu_name
FROM sys_menu
WHERE menu_name = #{menuName}
  AND parent_id = #{parentId}
  AND deleted = 0
LIMIT 1
